408   void copysign(const KnownFPClass &Sign) {
409     // Don't know anything about the sign of the source. Expand the possible set
410     // to its opposite sign pair.
411     if (KnownFPClasses & fcZero)
412       KnownFPClasses |= fcZero;
413     if (KnownFPClasses & fcSubnormal)
